import React, { useState } from "react";
import API from "../api/api";

/**
 * Compare two players side-by-side
 */

function PlayerComparison() {
  const [p1, setP1] = useState("");
  const [p2, setP2] = useState("");

  const [d1, setD1] = useState(null);
  const [d2, setD2] = useState(null);

  const [loading, setLoading] = useState(false);

  const comparePlayers = async () => {
    if (!p1 || !p2) return;

    setLoading(true);

    try {
      const r1 = await API.get(`/players/${p1}`);
      const r2 = await API.get(`/players/${p2}`);

      setD1(r1.data);
      setD2(r2.data);
    } catch (err) {
      console.error("Compare error:", err);
    }

    setLoading(false);
  };

  return (
    <div>
      <h2>⚔️ Player Comparison</h2>

      <input
        placeholder="Player 1"
        onChange={(e) => setP1(e.target.value)}
      />

      <input
        placeholder="Player 2"
        onChange={(e) => setP2(e.target.value)}
      />

      <button onClick={comparePlayers}>Compare</button>

      {loading && <p>Loading...</p>}

      {d1 && d2 && (
        <div className="card">
          <h3>{d1.name} vs {d2.name}</h3>
          <p>{d1.country} vs {d2.country}</p>
        </div>
      )}
    </div>
  );
}

export default PlayerComparison;
